import{_ as i,c as a,o as s,ak as t,ao as l}from"./chunks/framework.DHLlVITf.js";const g=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-119-0.md","filePath":"aireblock-releases/aireglu-v1-119-0.md","lastUpdated":1784549267000}'),n={name:"aireblock-releases/aireglu-v1-119-0.md"};function o(r,e,d,u,c,h){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+l+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.119.0<br><strong>Release Date:</strong> 29 July 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Support For Running Fluid V1 And V2 Side By Side (GLU-3127)</li><li>Fluid V2 Now Default For New Tasks (GLU-3128)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Single-Item XML Arrays Not Recognised In Liquid Mapping (GLU-505)</li><li>Fixed Conditional Liquid Evaluation For XML Elements With Attributes (GLU-2807)</li><li>Fixed Job Task Content Overflow Display Issue (GLU-3196)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="support-for-running-fluid-v1-and-v2-side-by-side-glu-3127" tabindex="-1">Support For Running Fluid V1 And V2 Side By Side (GLU-3127) <a class="header-anchor" href="#support-for-running-fluid-v1-and-v2-side-by-side-glu-3127" aria-label="Permalink to “Support For Running Fluid V1 And V2 Side By Side (GLU-3127)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Added support for running the Fluid V1 and Fluid V2 Liquid engines side by side, allowing the mapping engine used by a task to be selected based on the configured Liquid version.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now choose which Liquid engine version powers your mapping tasks, giving you more control and flexibility as newer capabilities become available.</p></div><h4 id="fluid-v2-now-default-for-new-tasks-glu-3128" tabindex="-1">Fluid V2 Now Default For New Tasks (GLU-3128) <a class="header-anchor" href="#fluid-v2-now-default-for-new-tasks-glu-3128" aria-label="Permalink to “Fluid V2 Now Default For New Tasks (GLU-3128)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>New tasks now default to the Fluid V2 Liquid engine, while existing tasks continue to use Fluid V1 by default.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Any new mapping tasks you create will automatically benefit from the latest Fluid V2 engine, while your existing tasks continue working exactly as before.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-single-item-xml-arrays-not-recognised-in-liquid-mapping-glu-505" tabindex="-1">Fixed Single-Item XML Arrays Not Recognised In Liquid Mapping (GLU-505) <a class="header-anchor" href="#fixed-single-item-xml-arrays-not-recognised-in-liquid-mapping-glu-505" aria-label="Permalink to “Fixed Single-Item XML Arrays Not Recognised In Liquid Mapping (GLU-505)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where an XML array containing only a single item was not recognised as an array during Liquid mapping, causing loop and array-based templates to behave incorrectly for single-item collections.</p></div><h4 id="fixed-conditional-liquid-evaluation-for-xml-elements-with-attributes-glu-2807" tabindex="-1">Fixed Conditional Liquid Evaluation For XML Elements With Attributes (GLU-2807) <a class="header-anchor" href="#fixed-conditional-liquid-evaluation-for-xml-elements-with-attributes-glu-2807" aria-label="Permalink to “Fixed Conditional Liquid Evaluation For XML Elements With Attributes (GLU-2807)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where conditional Liquid expressions evaluated incorrectly for XML elements that had attributes, even though printing those elements worked correctly.</p></div><h4 id="fixed-job-task-content-overflow-display-issue-glu-3196" tabindex="-1">Fixed Job Task Content Overflow Display Issue (GLU-3196) <a class="header-anchor" href="#fixed-job-task-content-overflow-display-issue-glu-3196" aria-label="Permalink to “Fixed Job Task Content Overflow Display Issue (GLU-3196)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a display issue where content within a Job Task rendered longer than its containing box, causing the content to overflow the UI.</p></div>',25)])])}const f=i(n,[["render",o]]);export{g as __pageData,f as default};
